# Basic dict comprehension
squares = {x: x**2 for x in range(6)}
print(squares)  # {0: 0, 1: 1, 2: 4, 3: 9, 4: 16, 5: 25}

# From two lists
keys = ["name", "age", "city"]
values = ["Alice", 30, "NYC"]
person = {k: v for k, v in zip(keys, values)}
print(person)  # {'name': 'Alice', 'age': 30, 'city': 'NYC'}
# Or simpler: dict(zip(keys, values))

# Filter entries
scores = {"Alice": 95, "Bob": 60, "Charlie": 85, "David": 45}
passing = {name: score for name, score in scores.items() if score >= 70}
print(passing)  # {'Alice': 95, 'Charlie': 85}

# Transform values
prices = {"apple": 1.00, "banana": 0.50, "cherry": 2.00}
taxed = {item: round(price * 1.08, 2) for item, price in prices.items()}
print(taxed)  # {'apple': 1.08, 'banana': 0.54, 'cherry': 2.16}

# Invert dict (swap keys and values)
original = {"a": 1, "b": 2, "c": 3}
inverted = {v: k for k, v in original.items()}
print(inverted)  # {1: 'a', 2: 'b', 3: 'c'}

# Transform keys
data = {"First Name": "Alice", "Last Name": "Smith"}
normalized = {k.lower().replace(" ", "_"): v for k, v in data.items()}
print(normalized)  # {'first_name': 'Alice', 'last_name': 'Smith'}

# Conditional value assignment
numbers = range(-5, 6)
sign_map = {n: ("positive" if n > 0 else "negative" if n < 0 else "zero") for n in numbers}
print(sign_map)  # {-5: 'negative', ..., 0: 'zero', ..., 5: 'positive'}

# Nested comprehension: flatten nested dict
nested = {"math": {"Alice": 95, "Bob": 87}, "science": {"Alice": 92, "Bob": 88}}
flat = {f"{subject}_{student}": grade
        for subject, students in nested.items()
        for student, grade in students.items()}
print(flat)  # {'math_Alice': 95, 'math_Bob': 87, 'science_Alice': 92, 'science_Bob': 88}

# Count character frequency
text = "hello world"
freq = {char: text.count(char) for char in set(text)}
print(freq)  # {'h': 1, 'e': 1, 'l': 3, 'o': 2, ...}

squares = {x: x**2 for x in range(5)}
print(squares)  # {0: 0, 1: 1, 2: 4, 3: 9, 4: 16}

# Filter
d = {"a": 1, "b": 2, "c": 3}
filtered = {k: v for k, v in d.items() if v > 1}
print(filtered)  # {'b': 2, 'c': 3}

d1 = {"a": 1, "b": 2}
d2 = {"b": 3, "c": 4}

# Method 1: update() -- modifies d1 in-place
merged = d1.copy()
merged.update(d2)
print(merged)  # {'a': 1, 'b': 3, 'c': 4}

# Method 2: ** unpacking (Python 3.5+)
merged = {**d1, **d2}
print(merged)  # {'a': 1, 'b': 3, 'c': 4}

# Can merge more than two
d3 = {"d": 5}
merged = {**d1, **d2, **d3}
print(merged)  # {'a': 1, 'b': 3, 'c': 4, 'd': 5}

# Method 3: | operator (Python 3.9+)
merged = d1 | d2
print(merged)  # {'a': 1, 'b': 3, 'c': 4}

# Method 4: |= in-place (Python 3.9+)
d1_copy = d1.copy()
d1_copy |= d2
print(d1_copy)  # {'a': 1, 'b': 3, 'c': 4}

# Deep merge (nested dicts)
def deep_merge(d1, d2):
    result = d1.copy()
    for key, value in d2.items():
        if key in result and isinstance(result[key], dict) and isinstance(value, dict):
            result[key] = deep_merge(result[key], value)
        else:
            result[key] = value
    return result

config_default = {"db": {"host": "localhost", "port": 5432}, "debug": False}
config_override = {"db": {"port": 3306}, "debug": True}

merged = deep_merge(config_default, config_override)
print(merged)  # {'db': {'host': 'localhost', 'port': 3306}, 'debug': True}

# ChainMap -- lazy merge (doesn't create new dict)
from collections import ChainMap
chain = ChainMap(d2, d1)  # d2 checked first
print(chain["a"])  # 1 (from d1)
print(chain["b"])  # 3 (from d2, found first)
print(dict(chain))  # {'a': 1, 'b': 3, 'c': 4}

